import os
import psutil
import shutil

def is_file_in_use(file_path):
    """Check if a file is in use by any running process."""
    for proc in psutil.process_iter(['pid', 'open_files']):
        try:
            info = proc.info
            for fd in info['open_files']:
                if fd['fd'] == os.open(file_path, os.O_RDONLY).fileno():
                    return True
        except (psutil.NoSuchProcess, psutil.AccessDenied, psutil.ZombieProcess):
            pass
    return False

def delete_temp_files(directory):
    """Recursively delete temporary files in a directory and its subdirectories."""
    for root, dirs, files in os.walk(directory):
        for file in files:
            file_path = os.path.join(root, file)
            if not is_file_in_use(file_path):
                try:
                    os.remove(file_path)
                    print(f"Deleted: {file_path}")
                except OSError as e:
                    print(f"Failed to delete {file_path}: {e}")

def main():
    home_dir = os.path.expanduser('~')
    temp_dir = os.path.join(home_dir, '.temp')
    if not os.path.exists(temp_dir):
        os.makedirs(temp_dir)
    delete_temp_files(temp_dir)

if __name__ == '__main__':
    main()
